mapper.select:
select
,e.exam_name as examName ,k.kecheng_name as kechengName from exam_question a left join exam e on a.exam_id = e.id left join kecheng k on coalesce(a.kecheng_id, e.kecheng_id) = k.id
and coalesce(a.kecheng_id, e.kecheng_id) = #{params.kechengId}
and a.exam_id = #{params.examId}
and (a.question_type = '选择题' or a.question_type = 'Choice')
and (a.question_type = '判断题' or a.question_type = 'True/False')
and (a.question_type = '填空题' or a.question_type = 'Fill in')
and (a.question_type = '简答题' or a.question_type = 'Short answer')
and a.question_type = #{params.questionType}
and a.question_title like concat('%',#{params.questionTitle},'%')
and e.jiaoshi_id = #{params.jiaoshiId}
and a.is_deleted = #{params.isDeleted}
order by a.${params.sort} ${params.order}
order by case when k.kecheng_name is null or k.kecheng_name = '' then 1 else 0 end asc, k.kecheng_name asc, case when a.question_type = '选择题' or a.question_type = 'Choice' then 1 when a.question_type = '判断题' or a.question_type = 'True/False' then 2 when a.question_type = '填空题' or a.question_type = 'Fill in' then 3 when a.question_type = '简答题' or a.question_type = 'Short answer' then 4 else 5 end asc, a.sort_no asc, a.id asc
